const items = $input.all();
const cutoff = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);

// 讀取歷史推薦清單（持久化在 staticData）
const staticData = $getWorkflowStaticData('global');
const excluded = staticData.previousRepos || [];
if (excluded.length > 0) {
  console.log('[去重] 排除已推薦過的', excluded.length, '個專案:', excluded.join(', '));
}

const filtered = (items[0].json.items || [])
  .filter(r => {
    if (!r.description || r.description.length < 10) return false;
    if (r.stargazers_count > 100000) return false; // 排除超大平台
    if (excluded.includes(r.full_name)) return false; // 排除已推薦過的
    const pushed = r.pushed_at ? new Date(r.pushed_at) : null;
    return pushed && pushed >= cutoff; // 90 天內有 commit
  })
  .slice(0, 15);

const repoList = filtered.map((r, i) => {
  const pushed = r.pushed_at ? r.pushed_at.split('T')[0] : '?';
  const created = r.created_at ? r.created_at.split('T')[0] : '?';
  return `${i+1}. ${r.full_name} (⭐${r.stargazers_count}, 最近commit:${pushed}, 建立:${created})\n   ${r.description}\n   ${r.html_url}`;
}).join('\n\n');

if (filtered.length === 0) {
  return [{ json: { repos: [], prompt: '', skip: true } }];
}

const prompt = `以下是 GitHub 上近 90 天內有活躍 commit 的 MCP Server 專案（MCP = Model Context Protocol，讓 AI 助理連接外部工具/服務）。

請挑選 5 個最實用的，評估時同時考量：
- ⭐ Stars 數（社群熱度）
- 📅 最近 commit 日期（維護活躍度）

對每個項目請用以下格式（繁體中文回應）：

**名稱**
🔧 功能：一句話說明能做什麼（不超過30字）
💡 場景：適合什麼使用情境
🔗 連結：直接附上 GitHub URL

MCP Server 清單：
${repoList}`;

return [{ json: { repos: filtered, prompt } }];

const geminiText = ($json.candidates?.[0]?.content?.parts?.[0]?.text) || '（Gemini 未回應）';
const today = new Date().toLocaleDateString('zh-TW', {timeZone:'Asia/Taipei',year:'numeric',month:'long',day:'numeric',weekday:'long'});
const header = `🔌 **MCP Server 週報** 🤖\n📅 ${today}\n\n`;
const footer = `\n\n> 資料來源：GitHub topic:mcp-server（90天活躍 · stars>50）`;
let content = header + geminiText + footer;
if (content.length > 1900) content = content.substring(0, 1897) + '...';
return [{ json: { content } }];

// 解析 Gemini 回傳文字，找出本週推薦的 repo full_name
const geminiText = $('Gemini 評估').first().json?.candidates?.[0]?.content?.parts?.[0]?.text || '';
const allRepos = $('準備 Gemini Prompt').first().json?.repos || [];

// 比對 Gemini 文字中出現了哪些 full_name
const mentioned = allRepos
  .filter(r => geminiText.includes(r.full_name))
  .map(r => r.full_name);

console.log('[去重] 本週推薦:', mentioned.join(', '));

// 更新 staticData，保留最近 4 週（20 個）
const staticData = $getWorkflowStaticData('global');
const prev = staticData.previousRepos || [];
staticData.previousRepos = [...prev, ...mentioned].slice(-20);

console.log('[去重] 累計排除清單:', staticData.previousRepos.join(', '));

return $input.all();

